import{_ as i,o as a,c as n,ag as r}from"./chunks/framework.ByAj6Cie.js";const h=JSON.parse('{"title":"Harmonics","description":"","frontmatter":{},"headers":[],"relativePath":"en/power-quality/harmonics.md","filePath":"en/power-quality/harmonics.md"}'),o={name:"en/power-quality/harmonics.md"};function t(s,e,l,c,d,m){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="harmonics" tabindex="-1">Harmonics <a class="header-anchor" href="#harmonics" aria-label="Permalink to &quot;Harmonics&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Harmonics are voltage or current components that occur at multiples of the fundamental frequency of the power system.</p><p>They distort the ideal sinusoidal waveform and are mainly caused by nonlinear loads.</p><p>Harmonics are a common power quality issue in modern industrial systems with widespread use of power electronics.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Understanding harmonics is important to:</p><ul><li>Maintain efficient and stable operation of electrical systems</li><li>Prevent overheating of equipment and conductors</li><li>Avoid malfunction of sensitive devices</li><li>Reduce losses and improve power quality</li></ul><p>Managing harmonics helps protect both equipment and system performance.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>In an ideal system, current and voltage follow a pure sinusoidal waveform at the fundamental frequency.</p><p>Nonlinear loads draw current in a non sinusoidal manner, creating additional frequency components.</p><p>These components are called harmonics and occur at integer multiples of the base frequency:</p><ul><li>2nd harmonic, 3rd harmonic, 5th harmonic, and so on</li></ul><p>Common sources of harmonics include:</p><ul><li>Variable frequency drives</li><li>Power supplies and rectifiers</li><li>UPS systems</li><li>LED lighting and electronic equipment</li></ul><p>These harmonic currents flow through the system and interact with impedance, causing voltage distortion.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Harmonics are relevant in:</p><ul><li>Industrial facilities with large numbers of drives and converters</li><li>Data centers and electronic intensive environments</li><li>Automation systems with sensitive control equipment</li><li>Facilities with significant nonlinear loads</li><li>Power systems requiring high power quality</li></ul><p>They are present in most modern electrical installations.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><p><strong>Harmonic order</strong><br> Lower order harmonics tend to have greater impact on the system</p></li><li><p><strong>Total distortion level</strong><br> Combined effect of all harmonics determines overall impact</p></li><li><p><strong>System impedance</strong><br> Influences how harmonics affect voltage distortion</p></li><li><p><strong>Resonance conditions</strong><br> Can amplify harmonic levels and create severe issues</p></li><li><p><strong>Equipment sensitivity</strong><br> Some devices are more affected by waveform distortion</p></li><li><p><strong>Mitigation methods</strong><br> Filters, reactors, and proper system design reduce harmonics</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Drives are one of the main sources of harmonics in industrial systems</li><li>Harmonics can cause overheating in transformers and neutral conductors</li><li>Capacitor banks can interact with harmonics and create resonance</li><li>Proper system design reduces harmonic propagation</li><li>Measurement is essential to identify harmonic problems and their sources</li></ul>',25)])])}const u=i(o,[["render",t]]);export{h as __pageData,u as default};
